<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Maze Pathfinding Bots</title>
    <style>
        body {
            background: #1a1a2e;
            color: #e94560;
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            margin: 0;
            height: 100vh;
            overflow: hidden;
        }
        #hud {
            display: flex;
            gap: 20px;
            margin-bottom: 15px;
            font-size: 1.2rem;
            font-weight: bold;
            text-transform: uppercase;
            letter-spacing: 1px;
        }
        #maze {
            background: #16213e;
            border: 4px solid #0f3460;
            box-shadow: 0 0 20px rgba(0,0,0,0.5);
            image-rendering: pixelated;
        }
        #reset {
            margin-top: 15px;
            padding: 10px 25px;
            background: #e94560;
            color: white;
            border: none;
            border-radius: 5px;
            cursor: pointer;
            font-weight: bold;
            transition: background 0.2s;
        }
        #reset:hover {
            background: #ff5e78;
        }
    </style>
</head>
<body>

    <div id="hud">
        <div>Completed: <span id="completed">0</span> / 24</div>
        <div>Time: <span id="timer">0</span>ms</div>
    </div>
    <canvas id="maze" width="500" height="500"></canvas>
    <button id="reset">Reset Game</button>

    <script>
        const canvas = document.getElementById('maze');
        const ctx = canvas.getContext('2d');
        const completedEl = document.getElementById('completed');
        const timerEl = document.getElementById('timer');
        const resetBtn = document.getElementById('reset');

        const GRID_SIZE = 20; // 20x20 cells
        const CELL_SIZE = canvas.width / GRID_SIZE;
        const BOT_COUNT = 24;

        let mazeWalls = []; // Stores walls for each cell: {top, right, bottom, left}
        let distMap = [];   // BFS distance from exit to every cell
        let startTime = 0;
        let lastFrameTime = 0;

        // Bot visual offsets so they don't look like a single dot (the "blob" requirement)
        const botOffsets = Array.from({ length: BOT_COUNT }, () => ({
            ox: Math.random() * CELL_SIZE - CELL_SIZE / 2,
            oy: Math.random() * CELL_SIZE - CELL_SIZE / 2,
            color: `hsl(${Math.random() * 360}, 70%, 60%)`
        }));

        window.game = {
            bots: [],
            completed: 0,
            elapsedMs: 0,
            tick(n) {
                for (let i = 0; i < n; i++) {
                    this.bots.forEach(bot => {
                        if (bot.x === GRID_SIZE - 1 && bot.y === GRID_SIZE - 1) return;

                        const currentDist = distMap[bot.y][bot.x];
                        let nextX = bot.x, nextY = bot.y;
                        let minDist = currentDist;

                        // Check neighbors to find the one closer to exit (BFS map)
                        const dirs = [
                            { dx: 0, dy: -1, wall: 'top' },
                            { dx: 1, dy: 0, wall: 'right' },
                            { dx: 0, dy: 1, wall: 'bottom' },
                            { dx: -1, dy: 0, wall: 'left' }
                        ];

                        for (const d of dirs) {
                            const nx = bot.x + d.dx;
                            const ny = bot.y + d.dy;
                            if (nx >= 0 && nx < GRID_SIZE && ny >= 0 && ny < GRID_SIZE) {
                                // Check if wall exists between current and neighbor
                                if (!mazeWalls[bot.y][bot.x][d.wall]) {
                                    if (distMap[ny][nx] < minDist) {
                                        minDist = distMap[ny][nx];
                                        nextX = nx;
                                        nextY = ny;
                                    }
                                }
                            }
                        }

                        bot.x = nextX;
                        bot.y = nextY;

                        if (bot.x === GRID_SIZE - 1 && bot.y === GRID_SIZE - 1) {
                            this.completed++;
                        }
                    });
                }
            },
            reset() {
                generateMaze();
                computeBFS();
                this.bots = Array.from({ length: BOT_COUNT }, () => ({ x: 0, y: 0 }));
                this.completed = 0;
                this.elapsedMs = 0;
                startTime = performance.now();
            }
        };

        function generateMaze() {
            mazeWalls = Array.from({ length: GRID_SIZE }, () => 
                Array.from({ length: GRID_SIZE }, () => ({ top: true, right: true, bottom: true, left: true }))
            );

            const visited = Array.from({ length: GRID_SIZE }, () => Array(GRID_SIZE).fill(false));
            const stack = [{ x: 0, y: 0 }];
            visited[0][0] = true;

            while (stack.length > 0) {
                const current = stack[stack.length - 1];
                const neighbors = [];
                const dirs = [
                    { dx: 0, dy: -1, wall: 'top', opp: 'bottom' },
                    { dx: 1, dy: 0, wall: 'right', opp: 'left' },
                    { dx: 0, dy: 1, wall: 'bottom', opp: 'top' },
                    { dx: -1, dy: 0, wall: 'left', opp: 'right' }
                ];

                for (const d of dirs) {
                    const nx = current.x + d.dx;
                    const ny = current.y + d.dy;
                    if (nx >= 0 && nx < GRID_SIZE && ny >= 0 && ny < GRID_SIZE && !visited[ny][nx]) {
                        neighbors.push({ x: nx, y: ny, wall: d.wall, opp: d.opp });
                    }
                }

                if (neighbors.length > 0) {
                    const next = neighbors[Math.floor(Math.random() * neighbors.length)];
                    mazeWalls[current.y][current.x][next.wall] = false;
                    mazeWalls[next.y][next.x][next.opp] = false;
                    visited[next.y][next.x] = true;
                    stack.push(next);
                } else {
                    stack.pop();
                }
            }
        }

        function computeBFS() {
            distMap = Array.from({ length: GRID_SIZE }, () => Array(GRID_SIZE).fill(Infinity));
            const queue = [{ x: GRID_SIZE - 1, y: GRID_SIZE - 1, d: 0 }];
            distMap[GRID_SIZE - 1][GRID_SIZE - 1] = 0;

            let head = 0;
            while (head < queue.length) {
                const { x, y, d } = queue[head++];
                const dirs = [
                    { dx: 0, dy: -1, wall: 'top' },
                    { dx: 1, dy: 0, wall: 'right' },
                    { dx: 0, dy: 1, wall: 'bottom' },
                    { dx: -1, dy: 0, wall: 'left' }
                ];

                for (const dir of dirs) {
                    const nx = x + dir.dx;
                    const ny = y + dir.dy;
                    if (nx >= 0 && nx < GRID_SIZE && ny >= 0 && ny < GRID_SIZE) {
                        // Check if there is a path between current and neighbor
                        // Note: we are moving backwards from exit, so check the wall of the neighbor
                        const wallToCheck = dir.wall === 'top' ? 'bottom' : 
                                            dir.wall === 'right' ? 'left' : 
                                            dir.wall === 'bottom' ? 'top' : 'right';

                        if (!mazeWalls[ny][nx][wallToCheck] && distMap[ny][nx] === Infinity) {
                            distMap[ny][nx] = d + 1;
                            queue.push({ x: nx, y: ny, d: d + 1 });
                        }
                    }
                }
            }
        }

        function draw() {
            ctx.clearRect(0, 0, canvas.width, canvas.height);

            // Draw Walls
            ctx.strokeStyle = '#4ecca3';
            ctx.lineWidth = 2;
            for (let y = 0; y < GRID_SIZE; y++) {
                for (let x = 0; x < GRID_SIZE; x++) {
                    const cell = mazeWalls[y][x];
                    const px = x * CELL_SIZE;
                    const py = y * CELL_SIZE;

                    ctx.beginPath();
                    if (cell.top) { ctx.moveTo(px, py); ctx.lineTo(px + CELL_SIZE, py); }
                    if (cell.right) { ctx.moveTo(px + CELL_SIZE, py); ctx.lineTo(px + CELL_SIZE, py + CELL_SIZE); }
                    if (cell.bottom) { ctx.moveTo(px, py + CELL_SIZE); ctx.lineTo(px + CELL_SIZE, py + CELL_SIZE); }
                    if (cell.left) { ctx.moveTo(px, py); ctx.lineTo(px, py + CELL_SIZE); }
                    ctx.stroke();
                }
            }

            // Draw Spawn and Exit
            ctx.fillStyle = 'rgba(0, 255, 0, 0.3)';
            ctx.fillRect(0, 0, CELL_SIZE, CELL_SIZE);
            ctx.fillStyle = 'rgba(255, 0, 0, 0.3)';
            ctx.fillRect((GRID_SIZE - 1) * CELL_SIZE, (GRID_SIZE - 1) * CELL_SIZE, CELL_SIZE, CELL_SIZE);

            // Draw Bots
            window.game.bots.forEach((bot, i) => {
                const offset = botOffsets[i];
                ctx.fillStyle = offset.color;
                ctx.beginPath();
                ctx.arc(
                    bot.x * CELL_SIZE + CELL_SIZE / 2 + offset.ox,
                    bot.y * CELL_SIZE + CELL_SIZE / 2 + offset.oy,
                    3, 0, Math.PI * 2
                );
                ctx.fill();
            });

            // Update HUD
            completedEl.textContent = window.game.completed;
            timerEl.textContent = Math.floor(window.game.elapsedMs);
        }

        function loop(now) {
            if (!lastFrameTime) lastFrameTime = now;
            const delta = now - lastFrameTime;
            lastFrameTime = now;

            window.game.elapsedMs += delta;

            // Simulation speed: 1 tick every ~200ms for visual clarity, but API can fast-forward
            if (Math.floor(now / 200) > Math.floor((now - delta) / 200)) {
                window.game.tick(1);
            }

            draw();
            requestAnimationFrame(loop);
        }

        resetBtn.addEventListener('click', () => window.game.reset());

        // Initialize and start
        window.game.reset();
        requestAnimationFrame(loop);
    </script>
</body>
</html>
